class Solution {
public:
    int longestSubarray(vector<int>& nums) {
        int onea = 0, oneb = 0, maxx = 0, test = 1;

        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] == 0) {
                test = 0;
                oneb = onea;
                onea = 0;
            } else {
                onea++;
            }
            maxx = max(maxx, onea + oneb);
        }
        if (test){
            maxx--;
        }
        return maxx;
    }
};
